  function readPrefixCatalog(source) {
    return String(source || "")
      .split(/\n+/)
      .map((line) => line.trim())
      .filter(Boolean)
      .map((line) => {
        const [firstRaw, packedRaw = ""] = line.split("=");
        const first = Number(firstRaw);
        const bucket = packedRaw
          .split("|")
          .filter(Boolean)
          .map((entry) => {
            const [secondRaw, kindRaw, labelRaw = ""] = entry.split(",");
            return [Number(secondRaw), (() => { try { return decodeURIComponent(labelRaw); } catch (_) { return labelRaw; } })(), Number(kindRaw)];
          });
        return [first, bucket];
      })
      .filter(([first, bucket]) => Number.isInteger(first) && Array.isArray(bucket));
  }

