  function toInt(v) {
    const n = Number.parseInt(v, 10);
    return Number.isFinite(n) ? n : NaN;
  }

  function normalizeIpText(raw) {
    const text = String(raw || "").trim();
    const matched = text.match(/\b\d{1,3}(?:\.\d{1,3}){1,3}\b/);
    if (!matched) return "";

    const chunks = matched[0].split(".").map((v) => String(toInt(v)));
    if (chunks.some((v) => v === "NaN")) return "";
    return chunks.join(".");
  }

  function prefixKey(ip) {
    const parts = String(ip || "").split(".");
    if (parts.length < 2) return "";
    const a = toInt(parts[0]);
    const b = toInt(parts[1]);
    if (!Number.isFinite(a) || !Number.isFinite(b)) return "";
    return `${a}.${b}`;
  }

  function buildPrefixLookup(rows) {
    const index = new Map();
    for (const [firstOctet, bucket] of rows) {
      for (const [secondOctet, provider, kind] of bucket || []) {
        index.set(`${firstOctet}.${secondOctet}`, {
          provider: String(provider || "정보없음"),
          kind: kind === 1 ? "mobile" : "wired"
        });
      }
    }
    return index;
  }

